                                icon={<TrendingUp size={24} />}
                                color="hsl(var(--primary))"
                                trend="+8.4%"
                            />
                            <AnalyticsCard
                                label="New Patients"
                                value={data?.registrations?.patients}
                                icon={<Users size={24} />}
                                color="hsl(var(--secondary))"
                                trend="+12.5%"
                            />
                            <AnalyticsCard
                                label="New Doctors"
                                value={data?.registrations?.doctors}
                                icon={<UserPlus size={24} />}
                                color="hsl(280, 70%, 55%)"
                                trend="+3.2%"
                            />
                            <AnalyticsCard
                                label="Appointments"
                                value={data?.appointments}
                                icon={<Calendar size={24} />}
                                color="hsl(45, 93%, 47%)"
                                trend="+24.8%"
                            />
                            <AnalyticsCard
