                                                    background: growthType === 'monthly' ? 'hsl(var(--card))' : 'transparent',
                                                    color: growthType === 'monthly' ? 'hsl(var(--primary))' : 'hsl(var(--muted-foreground))',
                                                    boxShadow: growthType === 'monthly' ? '0 4px 12px rgba(0,0,0,0.1)' : 'none',
