                                            {[1, 2, 3, 4].map(i => <div key={i} style={{ width: '100%', height: '1px', background: 'hsl(var(--border) / 0.5)' }}></div>)}
                                        </div>

                                        {(growthType === 'monthly' ? data?.user_stats?.monthly_growth : data?.user_stats?.yearly_growth)?.map((item, idx) => {
                                            const max = Math.max(...(growthType === 'monthly' ? data?.user_stats?.monthly_growth : data?.user_stats?.yearly_growth).map(d => d.count), 1);
                                            const height = (item.count / max) * 100;
                                            return (
                                                <div key={idx} style={{ flex: 1, height: '100%', display: 'flex', flexDirection: 'column', justifyContent: 'flex-end', alignItems: 'center', position: 'relative' }}>
                                                    <div
