            <div style={{ fontSize: '0.85rem', fontWeight: '800', color: 'hsl(var(--muted-foreground))', textTransform: 'uppercase', letterSpacing: '0.05em' }}>{label}</div>
        </div>
    </div>
);

export default ArchiveAnalytics;

import { useState, useEffect } from 'react';
import { api } from '../../services/api';
import {
    Download, FileText, TrendingUp, CreditCard, Banknote,
    ChevronLeft, RotateCcw, ShieldCheck, Zap, Activity
} from 'lucide-react';
import { useNavigate } from 'react-router-dom';

const FinancialLedger = () => {
    const navigate = useNavigate();
    const [loading, setLoading] = useState(true);
    const [data, setData] = useState({ patient_name: '', patient_id: '', ledger: [] });

    useEffect(() => {
        fetchLedger();
    }, []);

    const fetchLedger = async () => {
        try {
            const response = await api.get('/patient/ledger/');
            setData(response);
        } catch (error) {
            console.error("Failed to fetch financial ledger", error);
            if (error.data?.nexus_code === 'NP-404') {
                alert('Diagnostic Alert: Your patient profile artifact is missing in the clinical registry. Please contact specialized support.');
            } else {
                alert(`${error.message || 'Nexus Failure'}: Unable to synchronize ledger records.`);
            }
        } finally {
            setLoading(false);
        }
    };

    const handleDownloadPDF = async (txnId = null) => {
        try {
            const endpoint = txnId
                ? `/patient/ledger/pdf/?txn_id=${txnId}`
                : '/patient/ledger/pdf/';
            const blob = await api.getFile(endpoint);
            const url = window.URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = txnId ? `Receipt_${txnId}.pdf` : `Ledger_${data.patient_name}.pdf`;
            document.body.appendChild(a);
            a.click();
            window.URL.revokeObjectURL(url);
        } catch (error) {
            alert('Failed to generate statement. Clinical nexus busy.');
        }
    };

    const totalPaid = data.ledger.reduce((sum, item) => sum + item.total, 0);
    const totalTax = data.ledger.reduce((sum, item) => sum + item.tax, 0);

    if (loading) {
        return (
            <div className="dashboard-page flex-center">
                <div className="telemetry-loader">
                    <RotateCcw className="animate-spin" size={48} />
                    <p>Synchronizing Financial Records...</p>
                </div>
            </div>
        );
    }

    return (
        <div className="dashboard-page bg-gradient animate-fade-in">
            <div className="container" style={{ maxWidth: 'none', width: '98%' }}>

                {/* Header Protocol */}
                <header className="dashboard-header" style={{ marginBottom: '3rem' }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', marginBottom: '1.5rem' }}>
                        <button
                            onClick={() => navigate('/patient')}
                            className="btn btn-ghost"
                            style={{ padding: '0.75rem', borderRadius: '1rem' }}
                        >
                            <ChevronLeft size={24} />
                        </button>
                        <div className="header-badge">
                            <ShieldCheck size={14} /> Fiscal Statement Nexus
                        </div>
                    </div>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-end' }}>
                        <div>
                            <h1 className="header-title">Financial Ledger</h1>
                            <p className="header-subtitle">
                                Complete audit trail of clinical engagements for <strong>{data.patient_name}</strong> (ID: {data.patient_id})
                            </p>
                        </div>
                        <button
                            className="btn btn-primary animate-pulse-subtle"
                            style={{ gap: '0.75rem', padding: '1.25rem 2rem', borderRadius: '1.5rem' }}
                            onClick={() => handleDownloadPDF()}
                        >
                            <Download size={20} /> Download Statement (PDF)
                        </button>
                    </div>
                </header>

                {/* Performance Analytics Grid */}
                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '1.5rem', marginBottom: '3rem' }}>
                    <LedgerStat
                        label="Total Capital Invested"
                        value={`₹${totalPaid.toLocaleString()}`}
                        icon={<TrendingUp size={24} />}
                        color="hsl(var(--primary))"
                    />
                    <LedgerStat
                        label="Applicable Taxes (18%)"
                        value={`₹${totalTax.toLocaleString()}`}
                        icon={<Activity size={24} />}
                        color="hsl(215, 90%, 50%)"
                    />
                    <LedgerStat
                        label="Engagement Count"
                        value={data.ledger.length}
                        icon={<FileText size={24} />}
                        color="hsl(var(--secondary))"
                    />
                </div>

                {/* Transaction Matrix */}
                <div className="card" style={{ padding: '0', overflow: 'hidden', borderRadius: '2rem', border: '1px solid hsl(var(--border))' }}>
                    <div style={{ padding: '2rem', borderBottom: '1px solid hsl(var(--border))', background: 'hsl(var(--muted) / 0.3)' }}>
                        <h3 style={{ margin: 0, fontWeight: '800', fontSize: '1.25rem' }}>Transaction History</h3>
                    </div>
                    <div>
                        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
                            <thead>
                                <tr style={{ borderBottom: '1px solid hsl(var(--border))' }}>
                                    <th style={tableHeadStyle}>Date & Time</th>
                                    <th style={tableHeadStyle}>Transaction ID</th>
                                    <th style={tableHeadStyle}>Specialist</th>
                                    <th style={tableHeadStyle}>Protocol</th>
                                    <th style={tableHeadStyle}>Subtotal</th>
                                    <th style={tableHeadStyle}>GST (18%)</th>
                                    <th style={tableHeadStyle}>Total</th>
                                    <th style={{ ...tableHeadStyle, textAlign: 'right' }}>Actions</th>
                                </tr>
                            </thead>
                            <tbody>
                                {data.ledger.length > 0 ? data.ledger.map((item, idx) => (
                                    <tr key={idx} style={{
                                        borderBottom: '1px solid hsl(var(--border))',
                                        transition: 'background 0.2s'
                                    }}
                                        className="ledger-row"
                                    >
                                        <td style={tableCellStyle}>
                                            <div style={{ fontWeight: '700' }}>{item.date.split(' ')[0]}</div>
                                            <div style={{ fontSize: '0.75rem', color: 'hsl(var(--muted-foreground))' }}>{item.date.split(' ')[1]}</div>
                                        </td>
                                        <td style={{ ...tableCellStyle, fontFamily: 'monospace', fontSize: '0.8rem', opacity: 0.7 }}>
                                            {item.transaction_id}
                                        </td>
                                        <td style={tableCellStyle}>
                                            <div style={{ fontWeight: '800' }}>Dr. {item.doctor_name}</div>
                                            <div style={{ fontSize: '0.75rem', textTransform: 'uppercase', color: 'hsl(var(--primary))' }}>{item.doctor_specialty}</div>
                                        </td>
                                        <td style={tableCellStyle}>
                                            <span style={{
                                                display: 'inline-flex', alignItems: 'center', gap: '0.4rem',
                                                padding: '0.3rem 0.6rem', borderRadius: '0.6rem',
                                                background: 'hsl(var(--muted)/0.5)', fontSize: '0.7rem', fontWeight: '800'
                                            }}>
                                                {item.method === 'CASH' ? <Banknote size={12} /> : <CreditCard size={12} />}
                                                {item.method}
                                            </span>
                                        </td>
                                        <td style={tableCellStyle}>₹{item.subtotal.toFixed(2)}</td>
                                        <td style={tableCellStyle}>₹{item.tax.toFixed(2)}</td>
                                        <td style={{ ...tableCellStyle, fontWeight: '900', color: 'hsl(var(--primary))' }}>
                                            ₹{item.total.toFixed(2)}
                                        </td>
                                        <td style={{ ...tableCellStyle, textAlign: 'right' }}>
                                            <button
                                                onClick={() => handleDownloadPDF(item.transaction_id)}
                                                className="btn btn-ghost"
                                                style={{ padding: '0.5rem', borderRadius: '0.75rem', color: 'hsl(var(--primary))' }}
                                                title="Download Receipt"
                                            >
                                                <Download size={16} />
                                            </button>
                                        </td>
                                    </tr>
                                )) : (
                                    <tr>
                                        <td colSpan="7" style={{ padding: '4rem', textAlign: 'center' }}>
                                            <Zap size={48} style={{ opacity: 0.1, marginBottom: '1rem' }} />
                                            <p style={{ color: 'hsl(var(--muted-foreground))', fontWeight: '600' }}>No financial artifacts found in the clinical nexus.</p>
                                        </td>
                                    </tr>
                                )}
                            </tbody>
                        </table>
                    </div>
                </div>

                <style>{`
                    .flex-center { display: flex; align-items: center; justifyContent: center; minHeight: 60vh; text-align: center; }
                    .ledger-row:hover { background: hsl(var(--primary) / 0.02); }
                    .ledger-row:last-child { border-bottom: none; }
                    @keyframes pulse-subtle {
                        0% { transform: scale(1); }
                        50% { transform: scale(1.02); }
                        100% { transform: scale(1); }
                    }
                    .animate-pulse-subtle { animation: pulse-subtle 3s infinite ease-in-out; }
                `}</style>
            </div>
        </div>
    );
};

const LedgerStat = ({ label, value, icon, color }) => (
    <div className="card" style={{ padding: '2rem', border: '1px solid hsl(var(--border))', position: 'relative', overflow: 'hidden' }}>
        <div style={{ position: 'absolute', top: '-10px', right: '-10px', opacity: 0.03, transform: 'scale(2)' }}>{icon}</div>
        <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', marginBottom: '1.5rem' }}>
            <div style={{
                width: '44px', height: '44px', borderRadius: '1rem', background: `${color}10`, color: color,
                display: 'flex', alignItems: 'center', justifyContent: 'center'
            }}>
                {icon}
            </div>
            <span style={{ fontSize: '0.8rem', fontWeight: '800', color: 'hsl(var(--muted-foreground))', textTransform: 'uppercase', letterSpacing: '0.05em' }}>
                {label}
            </span>
        </div>
        <div style={{ fontSize: '2.5rem', fontWeight: '900', color: 'hsl(var(--foreground))' }}>{value}</div>
    </div>
);

const tableHeadStyle = {
    padding: '1.25rem 2rem',
    textAlign: 'left',
    fontSize: '0.75rem',
    fontWeight: '800',
    color: 'hsl(var(--muted-foreground))',
    textTransform: 'uppercase',
    letterSpacing: '0.05em'
};

const tableCellStyle = {
    padding: '1.5rem 2rem',
    fontSize: '0.9rem',
    fontWeight: '600'
};

export default FinancialLedger;

import { useState, useEffect, useRef } from 'react';
import { api } from '../../services/api';
import { useLocation } from 'react-router-dom';
import { FileText, Search, User, Download, Eye, Shield, FolderOpen, ChevronRight, HardDrive, Clock, ExternalLink, Calendar, PlusCircle, X, Send, Database, Zap } from 'lucide-react';

const MedicalRecords = () => {
    const location = useLocation();
    const [doctors, setDoctors] = useState([]);
    const [selectedDoctor, setSelectedDoctor] = useState(null);
    const [files, setFiles] = useState([]);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState(null);
    const [searchTerm, setSearchTerm] = useState('');
    const [showUploadModal, setShowUploadModal] = useState(false);
    const [uploadForm, setUploadForm] = useState({ type: '', file: null });
    const [uploading, setUploading] = useState(false);
    const fileInputRef = useRef(null);

    useEffect(() => {
        const initialize = async () => {
            const fetchedDoctors = await fetchAssignedDoctors();

            // Check for pre-selected doctor
            if (location.state?.doctorId) {
                const preSelected = fetchedDoctors.find(d => d.id === location.state.doctorId);
                if (preSelected) {
                    setSelectedDoctor(preSelected);
                }
            }
        };
        initialize();
    }, [location]);

    // Re-fetch files whenever selected doctor changes (filtering)
    useEffect(() => {
        fetchPatientFiles();
    }, [selectedDoctor]);


    const fetchAssignedDoctors = async () => {
        try {
            const response = await api.get('/appointments/');
            const appointmentList = Array.isArray(response) ? response : (response.appointments || []);
            const uniqueDoctors = {};
            appointmentList.forEach(apt => {
                if (!uniqueDoctors[apt.doctor_id]) {
                    uniqueDoctors[apt.doctor_id] = {
                        id: apt.doctor_id,
                        name: apt.doctor_name,
                        specialization: apt.doctor_specialization || 'Clinical Specialist'
                    };
                }
            });
            const doctorArray = Object.values(uniqueDoctors);
            setDoctors(doctorArray);
            return doctorArray;
        } catch (error) {
            console.error("Failed to fetch doctors", error);
            return [];
        }
    };

    const fetchPatientFiles = async () => {
        setLoading(true);
        setError(null);
        try {
            const url = selectedDoctor ? `/media/list?doctor_id=${selectedDoctor.id}` : '/media/list';
            const data = await api.get(url);
            setFiles(data);
        } catch (error) {
            console.error(error);
            setError(error.message || 'Transmission error encountered.');
        } finally {
            setLoading(false);
        }
    };


    const handleSelectDoctor = (doctor) => {
        setSelectedDoctor(doctor);
    };

    const handleUploadSubmit = async (e) => {
        e.preventDefault();
        if (!uploadForm.file) return alert('Please select a file to synchronize');
        if (!uploadForm.type) return alert('Please specify report type');

        setUploading(true);
        try {
            const formData = new FormData();
            formData.append('file', uploadForm.file);
            formData.append('description', uploadForm.type);
            if (selectedDoctor) {
                formData.append('doctor_id', selectedDoctor.id);
            }

            await api.uploadFile('/media/upload', formData);

            // If a doctor is selected, notify them
            if (selectedDoctor) {
                try {
                    await api.post('/notifications/', {
                        user_id: selectedDoctor.id,
                        notification_type: 'report_uploaded',
                        title: 'Diagnostic Data Received',
                        message: `A new ${uploadForm.type} has been synchronized to your clinical nexus by the patient.`
                    });
                } catch (notifErr) {
                    console.error("Notification failed", notifErr);
                }
            }

            alert('Telemetry synchronized successfully!');
            setShowUploadModal(false);
            setUploadForm({ type: '', file: null });
            fetchPatientFiles();
        } catch (error) {
            alert('Failed to synchronize data: ' + (error.message || 'Unknown error'));
        } finally {
            setUploading(false);
        }
    };

    const filteredDoctors = doctors.filter(d =>
        d.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
        d.specialization.toLowerCase().includes(searchTerm.toLowerCase())
    );

    const getFileUrl = (filePath) => api.getMediaUrl(`/media/${filePath}`);

    return (
        <div className="dashboard-page bg-gradient animate-fade-in">
            <div className="container dashboard-grid" style={{ flex: 1, alignItems: 'start' }}>

            {/* Terminal: Provider Registry */}
            <div className="glass-panel animate-slide-up dashboard-sidebar" style={{ display: 'flex', flexDirection: 'column', overflow: 'hidden', padding: '0', background: 'white', minHeight: '600px' }}>

                <div style={{ padding: '2.5rem', borderBottom: '1px solid hsl(var(--border))', background: 'linear-gradient(to bottom, hsl(var(--primary) / 0.03), transparent)' }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', color: 'hsl(var(--primary))', marginBottom: '1.5rem', fontWeight: '800', fontSize: '0.9rem', textTransform: 'uppercase', letterSpacing: '0.05em' }}>
                        <Shield size={18} /> Provider Registry
                    </div>
                    <h3 style={{ fontSize: '1.75rem', fontWeight: '800', marginBottom: '1.5rem' }}>Doctor <span className="gradient-text">Index</span></h3>
                    <div style={{ position: 'relative' }}>
                        <Search size={18} style={{ position: 'absolute', left: '1.25rem', top: '50%', transform: 'translateY(-50%)', color: 'hsl(var(--muted-foreground))' }} />
                        <input
                            type="text"
                            className="input"
                            placeholder="Find provider node..."
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            style={{ paddingLeft: '3.5rem', borderRadius: '1.25rem', height: '54px' }}
                        />
                    </div>
                </div>

                <div style={{ overflowY: 'auto', flex: 1, padding: '1.5rem' }}>
                    <div style={{ display: 'grid', gap: '1rem' }}>
                        {/* Global Vault Option */}
                        <div
                            onClick={() => setSelectedDoctor(null)}
                            style={{
                                padding: '1.5rem',
                                borderRadius: '1.25rem',
                                cursor: 'pointer',
                                background: !selectedDoctor ? 'hsl(var(--primary) / 0.08)' : 'white',
                                border: !selectedDoctor ? '1px solid hsl(var(--primary) / 0.2)' : '1px solid hsl(var(--border))',
                                transition: 'all 0.3s cubic-bezier(0.4, 0, 0.2, 1)',
                                display: 'flex',
                                alignItems: 'center',
                                gap: '1rem'
                            }}
                        >
                            <Database size={20} color={!selectedDoctor ? 'hsl(var(--primary))' : 'hsl(var(--muted-foreground))'} />
                            <div style={{ fontWeight: '800', color: !selectedDoctor ? 'hsl(var(--primary))' : 'inherit' }}>Global Medical Vault</div>
                        </div>

                        {filteredDoctors.map(doc => (
                            <div
                                key={doc.id}
                                onClick={() => handleSelectDoctor(doc)}
                                style={{
                                    padding: '1.5rem',
                                    borderRadius: '1.25rem',
                                    cursor: 'pointer',
                                    background: selectedDoctor?.id === doc.id ? 'hsl(var(--primary) / 0.08)' : 'white',
                                    border: selectedDoctor?.id === doc.id ? '1px solid hsl(var(--primary) / 0.2)' : '1px solid hsl(var(--border))',
                                    transition: 'all 0.3s cubic-bezier(0.4, 0, 0.2, 1)',
                                    display: 'flex',
                                    alignItems: 'center',
                                    justifyContent: 'space-between'
                                }}
                            >
                                <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
                                    <div style={{
                                        width: '44px', height: '44px', borderRadius: '1rem',
                                        background: selectedDoctor?.id === doc.id ? 'hsl(var(--primary))' : 'hsl(var(--muted))',
                                        color: selectedDoctor?.id === doc.id ? 'white' : 'hsl(var(--muted-foreground))',
                                        display: 'flex', alignItems: 'center', justifyContent: 'center',
                                        fontWeight: '800', transition: 'all 0.3s'
                                    }}>
                                        {doc.name[0]}
                                    </div>
                                    <div>
                                        <div style={{ fontWeight: '800', color: selectedDoctor?.id === doc.id ? 'hsl(var(--primary))' : 'inherit' }}>Dr. {doc.name}</div>
                                        <div style={{ fontSize: '0.75rem', color: 'hsl(var(--muted-foreground))', fontWeight: '600' }}>{doc.specialization}</div>
                                    </div>
                                </div>
                                <ChevronRight size={18} style={{ opacity: selectedDoctor?.id === doc.id ? 1 : 0.3 }} />
                            </div>
                        ))}
                    </div>
                </div>
            </div>

            {/* Console: Medical Vault */}
            <div className="glass-panel animate-slide-up dashboard-main" style={{ padding: '0', overflow: 'hidden', display: 'flex', flexDirection: 'column', background: 'white', minHeight: '600px' }}>
                <div style={{ padding: '3rem', borderBottom: '1px solid hsl(var(--border))', display: 'flex', flexWrap: 'wrap', gap: '1.5rem', justifyContent: 'space-between', alignItems: 'center', background: 'linear-gradient(to right, hsl(var(--secondary) / 0.05), transparent)' }}>

                    <div>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', color: 'hsl(var(--secondary))', marginBottom: '1rem', fontWeight: '800', fontSize: '0.8rem', textTransform: 'uppercase' }}>
                            <FolderOpen size={16} /> Clinical Repository
                        </div>
                        <h2 style={{ fontSize: '2.5rem', fontWeight: '800' }}>Record <span className="gradient-text">Vault</span></h2>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', marginTop: '0.5rem' }}>
                            <User size={16} color="hsl(var(--primary))" />
                            <span style={{ fontWeight: '700', color: 'hsl(var(--muted-foreground))' }}>
                                {selectedDoctor ? `Sharing with Dr. ${selectedDoctor.name}` : 'Personal Longitudinal Data'}
                            </span>
                        </div>
                    </div>
                    <button
                        onClick={() => setShowUploadModal(true)}
                        className="btn btn-primary"
                        style={{ borderRadius: '1rem', gap: '0.5rem', padding: '0.75rem 1.5rem' }}
                    >
                        <PlusCircle size={20} />
                        Sync Report
                    </button>
                </div>

                <div style={{ flex: 1, overflowY: 'auto', padding: '3rem' }}>
                    {loading ? (
                        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', gap: '2rem' }}>
                            {[1, 2, 3, 4].map(i => <div key={i} className="skeleton" style={{ height: '240px', borderRadius: '1.5rem' }}></div>)}
                        </div>
                    ) : error ? (
                        <div style={{ padding: '6rem 2rem', textAlign: 'center', background: 'hsl(346, 77%, 96%)', color: 'hsl(346, 77%, 49%)', borderRadius: '2rem', border: '1px solid hsl(346, 77%, 90%)' }}>
                            <Shield size={48} style={{ marginBottom: '1.5rem', opacity: 0.5 }} />
                            <h3 style={{ fontSize: '1.5rem', fontWeight: '800', marginBottom: '0.5rem' }}>Access Restricted</h3>
                            <p style={{ fontWeight: '600' }}>{error}</p>
                        </div>
                    ) : files.length === 0 ? (
                        <div style={{ padding: '6rem 2rem', textAlign: 'center', background: 'hsl(var(--muted) / 0.1)', borderRadius: '2rem' }}>
                            <Clock size={48} style={{ opacity: 0.1, marginBottom: '2rem' }} />
                            <h3 style={{ fontSize: '1.5rem', fontWeight: '800', marginBottom: '0.5rem' }}>Zero Telemetry</h3>
                            <p style={{ color: 'hsl(var(--muted-foreground))', fontWeight: '500' }}>No medical data packets have been uploaded to your ledger yet.</p>
                        </div>
                    ) : (
                        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))', gap: '2rem' }}>
                            {files.map(file => (
                                <div key={file.id} className="card animate-scale-in" style={{ padding: '0', overflow: 'hidden', border: '1px solid hsl(var(--border))' }}>
                                    <div style={{ padding: '2.5rem', background: 'hsl(var(--primary) / 0.03)', display: 'flex', justifyContent: 'center', position: 'relative' }}>
                                        <div style={{ padding: '1.25rem', background: 'white', borderRadius: '1.25rem', boxShadow: '0 10px 25px rgba(0,0,0,0.05)' }}>
                                            <FileText size={48} color="hsl(var(--primary))" />
                                        </div>
                                        <div style={{ position: 'absolute', top: '1rem', right: '1rem', opacity: 0.3 }}>
                                            <Zap size={16} />
                                        </div>
                                    </div>
                                    <div style={{ padding: '2rem' }}>
                                        <h4 style={{ fontSize: '1.1rem', fontWeight: '800', marginBottom: '0.5rem', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>
                                            {file.description || file.file_name}
                                        </h4>
                                        <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', color: 'hsl(var(--muted-foreground))', fontSize: '0.85rem', fontWeight: '600', marginBottom: '2rem' }}>
                                            <Calendar size={14} />
                                            {new Date(file.uploaded_at).toLocaleDateString('en-US', { day: 'numeric', month: 'short', year: 'numeric' })}
                                        </div>
                                        <a
                                            href={getFileUrl(file.file_path)}
                                            target="_blank"
                                            rel="noopener noreferrer"
                                            className="btn btn-primary"
                                            style={{ width: '100%', height: '48px', borderRadius: '1rem', fontWeight: '800', fontSize: '0.85rem', gap: '0.75rem' }}
                                        >
                                            <Download size={18} /> Retrieve Data
                                        </a>
                                    </div>
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            </div>

            {/* Sync Modal */}
            {showUploadModal && (
                <div style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.5)', backdropFilter: 'blur(8px)', zIndex: 1000, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                    <div className="glass-panel animate-scale-in" style={{ width: '500px', padding: '2.5rem', background: 'white' }}>
                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
                            <h3 style={{ fontSize: '1.5rem', fontWeight: '800' }}>Sync <span className="gradient-text">Diagnostics</span></h3>
                            <button onClick={() => setShowUploadModal(false)} style={{ background: 'none', border: 'none', color: 'hsl(var(--muted-foreground))', cursor: 'pointer' }}>
                                <X size={24} />
                            </button>
                        </div>

                        <form onSubmit={handleUploadSubmit}>
                            <div style={{ marginBottom: '1.5rem' }}>
                                <label style={{ display: 'block', marginBottom: '0.75rem', fontWeight: '700', fontSize: '0.9rem' }}>Report Type</label>
                                <select
                                    className="input"
                                    value={uploadForm.type}
                                    onChange={(e) => setUploadForm({ ...uploadForm, type: e.target.value })}
                                    style={{ width: '100%', height: '54px', borderRadius: '1rem', appearance: 'auto', paddingRight: '1rem' }}
                                    required
                                >
                                    <option value="">Select telemetry type...</option>
                                    <option value="Blood Report">Blood Report</option>
                                    <option value="Urine Report">Urine Report</option>
                                    <option value="X-Ray Scan">X-Ray Scan</option>
                                    <option value="MRI Scan">MRI Scan</option>
                                    <option value="CT Scan">CT Scan</option>
                                    <option value="ECG/EKG">ECG/EKG</option>
                                    <option value="Biopsy Report">Biopsy Report</option>
                                    <option value="General Health Report">General Health Report</option>
                                    <option value="Discharge Summary">Discharge Summary</option>
                                </select>
                            </div>

                            <div style={{ marginBottom: '2rem' }}>
                                <label style={{ display: 'block', marginBottom: '0.75rem', fontWeight: '700', fontSize: '0.9rem' }}>Select Document</label>
                                <div
                                    onClick={() => fileInputRef.current.click()}
                                    style={{
                                        width: '100%',
                                        padding: '2rem',
                                        border: '2px dashed hsl(var(--border))',
                                        borderRadius: '1rem',
                                        textAlign: 'center',
                                        cursor: 'pointer',
                                        background: 'hsl(var(--muted) / 0.1)',
                                        transition: 'var(--transition)'
                                    }}
                                    onMouseEnter={(e) => e.currentTarget.style.borderColor = 'hsl(var(--primary))'}
                                    onMouseLeave={(e) => e.currentTarget.style.borderColor = 'hsl(var(--border))'}
                                >
                                    <Upload size={32} color="hsl(var(--primary))" style={{ marginBottom: '1rem' }} />
                                    <p style={{ fontWeight: '600', fontSize: '0.9rem' }}>{uploadForm.file ? uploadForm.file.name : 'Click to select clinical shard'}</p>
                                </div>
                                <input
                                    ref={fileInputRef}
                                    type="file"
                                    hidden
                                    onChange={(e) => setUploadForm({ ...uploadForm, file: e.target.files[0] })}
                                />
                            </div>

                            <button
                                type="submit"
                                className="btn btn-primary"
                                disabled={uploading}
                                style={{ width: '100%', height: '54px', borderRadius: '1.25rem', fontWeight: '800', gap: '0.75rem' }}
                            >
                                {uploading ? 'Transmitting Shard...' : (
                                    <>
                                        <Send size={18} />
                                        Synchronize Data
                                    </>
                                )}
                            </button>
                        </form>
                    </div>
                </div>
            )}
            </div>
        </div>
    );
};


export default MedicalRecords;
function Upload(props) {
    return (
        <svg
            {...props}
            xmlns="http://www.w3.org/2000/svg"
            width="24"
            height="24"
            viewBox="0 0 24 24"
            fill="none"
            stroke="currentColor"
            strokeWidth="2"
            strokeLinecap="round"
            strokeLinejoin="round"
        >
            <path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4" />
            <polyline points="17 8 12 3 7 8" />
            <line x1="12" y1="3" x2="12" y2="15" />
        </svg>
    );
}

// ================= FRONTEND FILE =================
// File: PatientDashboard.jsx
// Purpose: Primary landing page for patients after login
// Handles: Displaying upcoming appointments, pending reschedules, and health telemetry summary

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import { api } from '../../services/api';
import { Calendar, Search, FileText, Activity, Clock, MapPin, User, ArrowRight, Stethoscope, ClipboardList, TrendingUp, Bell, ChevronRight, Zap, Star, Receipt, Download } from 'lucide-react';
import ReviewModal from '../../components/ReviewModal';
import StatusBadge from '../../components/StatusBadge';
import PaymentModal from '../../components/PaymentModal';
import { CreditCard, Banknote } from 'lucide-react';

const PatientDashboard = () => {
    const { user } = useAuth();
    const navigate = useNavigate();
    const [appointments, setAppointments] = useState([]);
    const [vaultCount, setVaultCount] = useState(0);
    const [loading, setLoading] = useState(true);
    const [selectedDoctor, setSelectedDoctor] = useState(null);
    const [isReviewOpen, setIsReviewOpen] = useState(false);
    const [payAppointment, setPayAppointment] = useState(null);
    const [recentReceipts, setRecentReceipts] = useState([]);

    useEffect(() => {
        fetchDashboardData();
    }, []);

    const fetchDashboardData = async () => {
        try {
            const [appointmentsData, recordsData, receiptsData] = await Promise.all([
                api.get('/appointments/'),
                api.get('/media/list'),
                api.get('/clinical-receipts/')
            ]);
            setAppointments(Array.isArray(appointmentsData) ? appointmentsData : []);
            setVaultCount(Array.isArray(recordsData) ? recordsData.length : 0);
            setRecentReceipts(Array.isArray(receiptsData) ? receiptsData.slice(0, 2) : []);
        } catch {
            console.error('Failed to fetch dashboard data');
        } finally {
            setLoading(false);
        }
    };

    const handleRescheduleResponse = async (id, action) => {
        try {
            await api.post(`/appointments/${id}/respond_reschedule/`, { action });
            fetchDashboardData();
            alert(`Reschedule proposal ${action}ed.`);
        } catch {
            alert('Failed to respond to reschedule.');
        }
    };

    const pendingReschedules = Array.isArray(appointments) ? appointments.filter(a => a?.status === 'reschedule_proposed') : [];

    const nextAppointment = appointments && Array.isArray(appointments)
        ? appointments
            .filter(app => app && app.appointment_date && new Date(app.appointment_date) >= new Date() && app.status !== 'reschedule_proposed')
            .sort((a, b) => new Date(a.appointment_date) - new Date(b.appointment_date))[0]
        : null;

    return (
        <div className="dashboard-page bg-gradient animate-fade-in">
            <div className="container">
                {/* 1. Dynamic Welcome Header */}
                <header className="dashboard-header">
                    <div className="dashboard-header-accent"></div>
                    <div className="dashboard-header-content">
                        <div className="header-badge">
                            <Zap size={14} /> Global Health Portal
                        </div>
                        <h1 className="header-title">
                            Health Sync, {user?.first_name}!
                        </h1>
                        <p className="header-subtitle">
                            Welcome back, {user?.first_name}. Your physiological telemetry is currently being synchronized with our clinical nexus.
                        </p>
                    </div>
                </header>

                {pendingReschedules.length > 0 && (
                    <div className="reschedule-alerts animate-fade-in" style={{ marginBottom: '2rem' }}>
                        {pendingReschedules.map(apt => (
                            <div key={apt.id} className="glass-card" style={{
                                borderLeft: '8px solid hsl(var(--primary))',
                                padding: '1.5rem',
                                display: 'flex',
                                justifyContent: 'space-between',
                                alignItems: 'center',
                                background: 'hsl(var(--primary) / 0.05)'
                            }}>
                                <div>
                                    <h4 style={{ margin: 0, fontWeight: '800' }}>Schedule Synchronization Request</h4>
                                    <p style={{ margin: '0.25rem 0 0', fontSize: '0.9rem', color: 'hsl(var(--muted-foreground))' }}>
                                        Dr. {apt.doctor_name} has proposed a new slot: <strong>{apt.proposed_date}</strong> at <strong>{apt.proposed_time}</strong>
                                    </p>
                                </div>
                                <div style={{ display: 'flex', gap: '1rem' }}>
                                    <button onClick={() => handleRescheduleResponse(apt.id, 'decline')} className="btn btn-outline" style={{ borderColor: 'hsl(0, 84.2%, 60.2%)', color: 'hsl(0, 84.2%, 60.2%)' }}>Decline</button>
                                    <button onClick={() => handleRescheduleResponse(apt.id, 'accept')} className="btn btn-primary">Accept & Sync</button>
                                </div>
                            </div>
                        ))}
                    </div>
                )}

                <div className="dashboard-grid">

                    {/* Main Content Area */}
                    <div className="dashboard-main">

                        {/* Next Action Widget */}
                        <div className="action-hub">
                            <div className="card-header-flex">
                                <h3 className="widget-title">Critical Path: Next Visit</h3>
                            </div>


                            {loading ? (
                                <div className="skeleton action-skeleton"></div>
                            ) : nextAppointment ? (
                                    <div className="card next-engagement-card animate-slide-up" style={{ display: 'grid', gridTemplateColumns: 'auto auto 1fr', alignItems: 'stretch', padding: '1rem', gap: '0.75rem', background: 'white', borderRadius: '2.5rem', border: 'none', boxShadow: '0 15px 35px -10px rgba(0,0,0,0.08)' }}>
                                        {/* 1. Date Section (Left) */}
                                        <div className="engagement-date-tag" style={{ width: '120px', height: '100%', display: 'flex', flexDirection: 'column', justifyContent: 'center', alignItems: 'center', background: 'hsl(var(--primary))', color: 'white', borderRadius: '1.75rem' }}>
                                            <span className="date-day" style={{ fontSize: '2.5rem', fontWeight: '950', lineHeight: 1, color: 'white' }}>
                                                {new Date(nextAppointment.appointment_date).getDate()}
                                            </span>
                                            <span className="date-month" style={{ fontSize: '0.85rem', fontWeight: '800', textTransform: 'uppercase', marginTop: '0.25rem', letterSpacing: '0.15em', opacity: 0.9, color: 'white' }}>
                                                {new Date(nextAppointment.appointment_date).toLocaleString('default', { month: 'short' })}
                                            </span>
                                        </div>

                                        {/* 2. Doctor Information (Center) */}
                                        <div className="engagement-details" style={{ width: '280px', display: 'flex', flexDirection: 'column', alignItems: 'center', textAlign: 'center', background: 'hsl(var(--primary) / 0.03)', padding: '1.25rem', borderRadius: '1.75rem', border: '1px solid hsl(var(--primary) / 0.05)', justifyContent: 'center' }}>
                                            <div style={{ width: '64px', height: '64px', borderRadius: '1.25rem', overflow: 'hidden', border: '3px solid white', boxShadow: '0 8px 16px rgba(0,0,0,0.08)', background: 'hsl(var(--muted))', display: 'flex', alignItems: 'center', justifyContent: 'center', marginBottom: '0.75rem' }}>
                                                {nextAppointment.doctor_profile_picture ? (
                                                    <img 
                                                        src={api.getMediaUrl(nextAppointment.doctor_profile_picture)} 
                                                        alt="Doctor" 
                                                        style={{ width: '100%', height: '100%', objectFit: 'cover' }}
                                                        onError={(e) => {
                                                            e.target.style.display = 'none';
                                                            e.target.parentElement.innerHTML = '<div style="color: hsl(var(--primary)); font-weight: 950; font-size: 1.25rem;">' + (nextAppointment.doctor_name?.[0] || 'D') + '</div>';
                                                        }}
                                                    />
                                                ) : (
                                                    <div style={{ color: 'hsl(var(--primary))', fontWeight: '950', fontSize: '1.25rem' }}>
                                                        {nextAppointment.doctor_name?.[0] || 'D'}
                                                    </div>
                                                )}
                                            </div>
                                            <h2 style={{ fontSize: '1.25rem', fontWeight: '900', color: 'hsl(var(--foreground))', margin: '0 0 0.2rem', letterSpacing: '-0.02em' }}>Dr. {nextAppointment.doctor_name}</h2>
                                            <div style={{ fontSize: '0.8rem', fontWeight: '700', color: 'hsl(var(--muted-foreground))', display: 'flex', alignItems: 'center', gap: '0.3rem', opacity: 0.8 }}>
                                                <MapPin size={12} style={{ color: 'hsl(var(--secondary))' }} />
                                                {nextAppointment.hospital_name || 'Medical Hub'}
                                            </div>
                                            <div style={{ marginTop: '0.5rem', padding: '0.3rem 0.75rem', background: 'hsl(var(--primary) / 0.08)', borderRadius: '1rem', fontSize: '0.75rem', fontWeight: '900', color: 'hsl(var(--primary))', display: 'flex', alignItems: 'center', gap: '0.35rem' }}>
                                                <div style={{ width: '5px', height: '5px', borderRadius: '50%', background: 'hsl(var(--primary))', animation: 'ping 1.5s infinite' }}></div>
                                                LIVE @ {nextAppointment.appointment_time}
                                            </div>
                                        </div>
                                        
                                        {/* 3. Queue Indicators (Right) */}
                                        <div className="queue-insights" style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '0.75rem' }}>
                                            <div style={{ background: 'hsl(var(--foreground))', color: 'white', padding: '1rem', borderRadius: '1.75rem', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', textAlign: 'center' }}>
                                                <div style={{ fontSize: '0.6rem', fontWeight: '900', color: 'hsl(var(--primary))', letterSpacing: '0.12em', marginBottom: '0.4rem', textTransform: 'uppercase', opacity: 0.9 }}>YOUR TOKEN</div>
                                                <span style={{ fontSize: '1.6rem', fontWeight: '900' }}>{nextAppointment.token_number || 'WAITING'}</span>
                                            </div>

                                             <div style={{ background: 'hsl(var(--primary) / 0.04)', border: '1px solid hsl(var(--primary) / 0.08)', padding: '1rem', borderRadius: '1.75rem', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', textAlign: 'center' }}>
                                                <div style={{ fontSize: '0.55rem', fontWeight: '900', color: 'hsl(var(--muted-foreground))', letterSpacing: '0.1em', marginBottom: '0.4rem', textTransform: 'uppercase', opacity: 0.8 }}>NOW SERVING</div>
                                                <span style={{ fontSize: '1.3rem', fontWeight: '950', color: 'hsl(var(--primary))', letterSpacing: '-0.02em' }}>{nextAppointment?.serving_token || 'TKN-001'}</span>
                                            </div>

                                            <div style={{ background: 'hsl(var(--secondary) / 0.04)', border: '1px solid hsl(var(--secondary) / 0.08)', padding: '1rem', borderRadius: '1.75rem', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', textAlign: 'center' }}>
                                                <div style={{ fontSize: '0.55rem', fontWeight: '900', color: 'hsl(var(--muted-foreground))', letterSpacing: '0.1em', marginBottom: '0.4rem', textTransform: 'uppercase', opacity: 0.8 }}>PEOPLE AHEAD</div>
                                                <span style={{ fontSize: '1.3rem', fontWeight: '950', color: 'hsl(var(--secondary))' }}>{nextAppointment?.tokens_ahead || '0'}</span>
                                            </div>
                                        </div>
                                    </div>
                            ) : (
                                <div className="glass-panel empty-widget">
                                    <Calendar size={48} className="empty-icon" />
                                    <h3 className="empty-title">No Upcoming Engagements</h3>
                                    <p className="empty-desc">Explore our network to schedule your next wellness check.</p>
                                </div>
                            )}
                        </div>



                        {/* Service Hub */}
                        <div className="service-hub">
                            <h3 className="widget-title">Ecosystem Navigation</h3>
                            <div className="service-card-grid">
                                <ServiceCard
                                    icon={<Search size={28} />}
                                    title="Doctor Search"
                                    desc="Locate specialists across our medical nexus."
                                    color="hsl(var(--primary))"
                                    onClick={() => navigate('/patient/search')}
                                />
                                <ServiceCard
                                    icon={<Activity size={28} />}
                                    title="AI Symptom Checker"
                                    desc="Analyze physiological anomalies with AI."
                                    color="hsl(var(--secondary))"
                                    onClick={() => navigate('/patient/symptom-checker')}
                                />
                                <ServiceCard
                                    icon={<ClipboardList size={28} />}
                                    title="Vault Records"
                                    desc="Access your secured clinical documentation."
                                    color="hsl(var(--accent))"
                                    onClick={() => navigate('/patient/records')}
                                />
                                <ServiceCard
                                    icon={<CreditCard size={28} />}
                                    title="Financial Ledger"
                                    desc="Monitor transactional health balances."
                                    color="hsl(142, 70%, 45%)"
                                    onClick={() => navigate('/patient/ledger')}
                                />
                                <ServiceCard
                                    icon={<Receipt size={28} />}
                                    title="Clinical Receipts"
                                    desc="Download verifiable medical invoices."
                                    color="hsl(262, 80%, 50%)"
                                    onClick={() => navigate('/patient/receipts')}
                                />
                            </div>
                        </div>
                    </div>

                    {/* Sidebar Area */}
                    <div className="dashboard-sidebar">

                        {/* Profile Card */}
                        <div className="card profile-overview-card">
                            <div className="profile-avatar-container" style={{ overflow: 'hidden' }}>
                                {user?.profile_picture ? (
                                    <img src={api.getMediaUrl(user.profile_picture)} alt="Profile" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                                ) : (
                                    <User size={44} />
                                )}
                            </div>
                            <h3 className="profile-name">{user?.first_name} {user?.last_name}</h3>
                            <p className="profile-id">Identity: SS-{(user?.id || user?._id || '000000').toString().slice(-6)}</p>

                            <div className="profile-stats">
                                <div className="stat-pill">
                                     <div className="pill-value primary">{Array.isArray(appointments) ? appointments.length : 0}</div>
                                    <div className="pill-label">Visits</div>
                                </div>
                                <div className="stat-pill-divider"></div>
                                <div className="stat-pill">
                                    <div className="pill-value secondary">{vaultCount}</div>
                                    <div className="pill-label">Vaults</div>
                                </div>
                            </div>
                        </div>

                        {/* Timeline Feed */}
                        <div className="card timeline-card">
                            <div className="timeline-header">
                                <h4 className="timeline-title">Medical Timeline</h4>
                                <Bell size={16} className="timeline-icon" />
                            </div>
                            <div className="timeline-body">
                                {loading ? (
                                    <div className="timeline-loading">Synchronizing...</div>
                                ) : (Array.isArray(appointments) && appointments.length > 0) ? (
                                    appointments.slice(0, 4).map((app, i) => (
                                        <div key={i} className="timeline-item">
                                            <div className={`timeline-icon-box ${app.status === 'completed' ? 'active' : ''}`}>
                                                {app.doctor_profile_picture ? (
                                                    <img 
                                                        src={api.getMediaUrl(app.doctor_profile_picture)} 
                                                        alt="Doctor" 
                                                        style={{ width: '100%', height: '100%', objectFit: 'cover' }}
                                                        onError={(e) => {
                                                            e.target.style.display = 'none';
                                                            e.target.parentElement.innerHTML = '<div style="color: inherit; font-weight: 800; font-size: 0.8rem;">' + (app.doctor_name?.[0] || 'D') + '</div>';
                                                        }}
                                                    />
                                                ) : (
                                                    <div style={{ color: 'inherit', fontWeight: '800', fontSize: '0.8rem' }}>
                                                        {app.doctor_name?.[0] || 'D'}
                                                    </div>
                                                )}
                                            </div>
                                            <div className="timeline-content">
                                                <div className="timeline-doctor">
                                                    Dr. {app.doctor_name}
                                                    {app.token_number && (
                                                        <span style={{ marginLeft: '0.75rem', fontSize: '0.65rem', color: 'hsl(var(--primary))', fontWeight: '900', background: 'hsl(var(--primary)/0.08)', padding: '0.15rem 0.5rem', borderRadius: '0.5rem', verticalAlign: 'middle' }}>
                                                            {app.token_number}
                                                        </span>
                                                    )}
                                                </div>
                                                <div className="timeline-date">{app.appointment_date}</div>
                                            </div>
                                            <div className="timeline-badges" style={{ display: 'flex', alignItems: 'center', gap: '0.6rem', marginLeft: 'auto' }}>
                                                <StatusBadge status={app.status} />
                                                {app.is_paid && (
                                                    <div style={{
                                                        fontSize: '0.6rem', fontWeight: '900', color: 'hsl(var(--primary))',
                                                        background: 'hsl(var(--primary) / 0.05)', padding: '0.2rem 0.4rem',
                                                        borderRadius: '0.4rem', border: '1px solid hsl(var(--primary) / 0.1)',
                                                        textTransform: 'uppercase', letterSpacing: '0.05em'
                                                    }}>
                                                        PAID
                                                    </div>
                                                )}
                                            </div>
                                            {app.status === 'accepted' && !app.is_paid && (
                                                <button
                                                    onClick={() => setPayAppointment(app)}
                                                    className="btn btn-primary"
                                                    style={{ padding: '0.4rem 0.8rem', fontSize: '0.75rem', borderRadius: '0.6rem', gap: '0.4rem' }}
                                                >
                                                    <CreditCard size={14} /> Pay Now
                                                </button>
                                            )}
                                            {app.status === 'completed' && !app.is_reviewed && (
                                                <button
                                                    onClick={() => {
                                                        setSelectedDoctor(app);
                                                        setIsReviewOpen(true);
                                                    }}
                                                    className="btn-review"
                                                    title="Submit Performance Review"
                                                >
                                                    <Star size={14} fill="currentColor" />
                                                </button>
                                            )}
                                        </div>
                                    ))
                                ) : (
                                    <div className="timeline-empty">
                                        No historical data available.
                                    </div>
                                )}
                            </div>
                            <button
                                className="btn btn-ghost timeline-footer-btn"
                                onClick={() => navigate('/patient/archive')}
                            >
                                Archive Analytics <ChevronRight size={18} />
                            </button>
                        </div>
                    </div>
                </div>

                {payAppointment && (
                    <PaymentModal
                        amount={payAppointment.amount || 500}
                        appointmentId={payAppointment.id}
                        onClose={() => setPayAppointment(null)}
                        onSuccess={() => {
                            setPayAppointment(null);
                            fetchDashboardData();
                        }}
                    />
                )}

                {selectedDoctor && (
                    <ReviewModal
                        isOpen={isReviewOpen}
                        onClose={() => {
                            setIsReviewOpen(false);
                            setSelectedDoctor(null);
                        }}
                        appointment={selectedDoctor}
                        onSuccess={() => {
                            alert('Performance intelligence logged successfully.');
                            fetchDashboardData();
                        }}
                    />
                )}
            </div>
        </div>
    );
};

// --- Specialized Components ---

const ServiceCard = ({ icon, title, desc, color, onClick }) => (
    <div 
        className="service-card" 
        onClick={onClick}
        style={{ '--hover-color': color, '--hover-shadow': `${color}30` }}
    >
        <div className="service-card-icon-box" style={{ background: color, boxShadow: `0 10px 20px ${color}30` }}>
            {icon}
        </div>
        <h4 className="service-card-title">{title}</h4>
        <p className="service-card-desc">{desc}</p>
    </div>
);

export default PatientDashboard;

import React, { useState, useEffect } from 'react';
import { useLocation } from 'react-router-dom';
import { api } from '../../services/api';
import { Search, MapPin, User, Calendar, Filter, Star, ShieldCheck, ChevronRight, Zap, Award, BookOpen, X, Clock, MessageSquare } from 'lucide-react';
import BookingModal from '../../components/BookingModal';
import Modal from '../../components/Modal';

const SearchDoctors = () => {
    const [doctors, setDoctors] = useState([]);
    const [filteredDoctors, setFilteredDoctors] = useState([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');
    const [specializationFilter, setSpecializationFilter] = useState('');
    const [selectedDoctor, setSelectedDoctor] = useState(null);
    const [portfolioDoctor, setPortfolioDoctor] = useState(null);
    const location = useLocation();

    const specializations = [...new Set((doctors || []).map(d => d?.specialization).filter(Boolean))];

    useEffect(() => {
        fetchDoctors();
        // Check for incoming filters from AI Bot
        if (location.state?.query) {
            setSpecializationFilter(location.state.query);
        }
    }, [location.state]);

    useEffect(() => {
        filterDoctors();
    }, [searchTerm, specializationFilter, doctors]);

    const fetchDoctors = async () => {
        try {
            const data = await api.get('/doctors/search/');
            setDoctors(data);
            setFilteredDoctors(data);
        } catch (err) {
            console.error(err);
        } finally {
            setLoading(false);
        }
    };

    const filterDoctors = () => {
        let result = doctors;

        if (searchTerm) {
            const lowerTerm = searchTerm.toLowerCase();
            result = result.filter(d =>
                d.doctor_name.toLowerCase().includes(lowerTerm) ||
                d.specialization.toLowerCase().includes(lowerTerm)
            );
        }

        if (specializationFilter) {
            result = result.filter(d => d.specialization?.toLowerCase() === specializationFilter.toLowerCase());
        }

        setFilteredDoctors(result);
    };

    const handleBook = (doctor) => {
        setSelectedDoctor(doctor);
    };

    const handleBookingSuccess = () => {
        alert('Appointment Scheduled Successfully!');
    };

    return (
        <div className="bg-gradient animate-fade-in" style={{ padding: '4rem 1.5rem', flex: 1 }}>
            <div className="container">
                <header style={{ marginBottom: '3.5rem' }}>
                    <div style={{ display: 'inline-flex', alignItems: 'center', gap: '0.5rem', background: 'hsl(var(--primary) / 0.1)', color: 'hsl(var(--primary))', padding: '0.4rem 1.25rem', borderRadius: '2rem', marginBottom: '1.25rem', fontWeight: '700', fontSize: '0.85rem', textTransform: 'uppercase', letterSpacing: '0.05em' }}>
                        <Zap size={16} /> Verified Specialists
                    </div>
                    <h1 style={{ fontSize: '3.5rem', marginBottom: '0.75rem', fontWeight: '800' }}>Find Your <span className="gradient-text">Care Partner</span></h1>
                    <p style={{ color: 'hsl(var(--muted-foreground))', fontSize: '1.2rem', maxWidth: '600px' }}>
                        Connect with top-tier medical experts across multiple disciplines.
                    </p>
                </header>

                {/* Search & Intelligence Controls */}
                <div style={{
                    display: 'flex',
                    gap: '1.5rem',
                    marginBottom: '3rem',
                    flexWrap: 'wrap',
                    background: 'white',
                    padding: '1.5rem',
                    borderRadius: '2rem',
                    boxShadow: 'var(--shadow-lg)',
                    border: '1px solid hsl(var(--border))'
                }}>
                    <div style={{ position: 'relative', flex: 2, minWidth: '300px' }}>
                        <Search size={22} style={{ position: 'absolute', left: '1.25rem', top: '50%', transform: 'translateY(-50%)', color: 'hsl(var(--primary))' }} />
                        <input
                            type="text"
                            className="input"
                            placeholder="Enter doctor name, specialization, or keyword..."
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            style={{ paddingLeft: '3.5rem', height: '60px', borderRadius: '1.25rem', fontSize: '1.1rem', background: 'hsl(var(--muted) / 0.3)', border: 'none' }}
                        />
                    </div>

                    <div style={{ position: 'relative', flex: 1, minWidth: '220px' }}>
                        <Filter size={20} style={{ position: 'absolute', left: '1.25rem', top: '50%', transform: 'translateY(-50%)', color: 'hsl(var(--secondary))' }} />
                        <select
                            className="input"
                            value={specializationFilter}
                            onChange={(e) => setSpecializationFilter(e.target.value)}
                            style={{ paddingLeft: '3.5rem', height: '60px', borderRadius: '1.25rem', appearance: 'none', background: 'hsl(var(--muted) / 0.3)', border: 'none', fontWeight: '600' }}
                        >
                            <option value="">All Shards</option>
                            {specializations.map(spec => (
                                <option key={spec} value={spec}>{spec}</option>
                            ))}
                        </select>
                    </div>
                </div>

                {/* Results Matrix */}
                {loading ? (
                    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(340px, 1fr))', gap: '2rem' }}>
                        {[1, 2, 3, 4, 5, 6].map(i => <div key={i} className="skeleton" style={{ height: '320px', borderRadius: '2rem' }}></div>)}
                    </div>
                ) : (
                    <div style={{
                        display: 'grid',
                        gridTemplateColumns: 'repeat(auto-fill, minmax(340px, 1fr))',
                        gap: '2.5rem'
                    }}>
                        {filteredDoctors.map(doctor => (
                            <DoctorCard
                                key={doctor.id}
                                doctor={doctor}
                                onBook={() => handleBook(doctor)}
                                onViewPortfolio={() => setPortfolioDoctor(doctor)}
                            />
                        ))}
                        {filteredDoctors.length === 0 && (
                            <div style={{ gridColumn: '1/-1', textAlign: 'center', padding: '6rem', color: 'hsl(var(--muted-foreground))' }}>
                                <User size={48} style={{ opacity: 0.2, marginBottom: '1.5rem' }} />
                                <h3 style={{ fontSize: '1.5rem', fontWeight: '800' }}>No Profiles Detected</h3>
                                <p>Adjust your parameters to expand the search scope.</p>
                            </div>
                        )}
                    </div>
                )}

                {selectedDoctor && (
                    <BookingModal
                        doctor={selectedDoctor}
                        onClose={() => setSelectedDoctor(null)}
                        onSuccess={handleBookingSuccess}
                    />
                )}

                {portfolioDoctor && (
                    <PortfolioModal
                        doctor={portfolioDoctor}
                        onClose={() => setPortfolioDoctor(null)}
                    />
                )}
            </div>
        </div>
    );
};

const DoctorCard = ({ doctor, onBook, onViewPortfolio }) => (
    <div className="card animate-slide-up" style={{ padding: '2.5rem', transition: 'var(--transition)', border: '1px solid hsl(var(--border))', boxShadow: 'var(--shadow-md)', display: 'flex', flexDirection: 'column', height: '100%' }}>
        <div style={{ display: 'flex', gap: '1.5rem', marginBottom: '2rem' }}>
            <div style={{ position: 'relative' }}>
                <div style={{
                    width: '80px',
                    height: '80px',
                    borderRadius: '2rem',
                    background: 'hsl(var(--muted))',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    boxShadow: 'var(--shadow-sm)',
                    overflow: 'hidden'
                }}>
                    {doctor.profile_picture ? (
                        <img src={api.getMediaUrl(doctor.profile_picture)} alt="Doctor" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                    ) : (
                        <User size={36} style={{ color: 'hsl(var(--primary))' }} />
                    )}
                </div>
                <div style={{ position: 'absolute', bottom: '-5px', right: '-5px', background: 'white', borderRadius: '50%', padding: '4px', boxShadow: 'var(--shadow-sm)' }}>
                    <ShieldCheck size={18} style={{ color: '#22c55e' }} fill="#22c55e20" />
                </div>
            </div>
            <div style={{ flex: 1 }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '0.3rem', color: '#f59e0b', fontSize: '0.85rem', fontWeight: '800', marginBottom: '0.25rem' }}>
                    <Star size={14} fill="#f59e0b" /> {doctor.average_rating} ({doctor.review_count}+ reviews)
                </div>
                <h3 style={{ fontSize: '1.4rem', fontWeight: '800', marginBottom: '0.25rem' }}>Dr. {doctor.doctor_name}</h3>
                <p style={{ color: 'hsl(var(--secondary))', fontWeight: '700', fontSize: '0.95rem', textTransform: 'uppercase', letterSpacing: '0.05em' }}>
                    {doctor.specialization}
                </p>
            </div>
        </div>

        <p style={{ color: 'hsl(var(--muted-foreground))', fontSize: '0.95rem', marginBottom: '1.5rem', lineHeight: '1.6', flex: '1' }}>
            {doctor.description || "Certified medical professional dedicated to providing high-quality clinical care and patient-centric treatment strategies."}
        </p>

        <div style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem', marginBottom: '2.5rem' }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', fontSize: '0.95rem', color: 'hsl(var(--muted-foreground))', fontWeight: '600' }}>
                <MapPin size={18} style={{ color: 'hsl(var(--primary))' }} />
                <span>Central Medical Complex</span>
            </div>
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', fontSize: '0.95rem', color: 'hsl(var(--muted-foreground))', fontWeight: '600' }}>
                <Calendar size={18} style={{ color: 'hsl(var(--secondary))' }} />
                <span>Next Slot: Tomorrow</span>
            </div>
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', fontSize: '1rem', color: 'hsl(var(--foreground))', fontWeight: '800', marginTop: '0.5rem' }}>
                <Zap size={18} style={{ color: '#f59e0b' }} />
                <span>Fee: ₹{doctor.consultation_fee || '500'}</span>
            </div>
        </div>

        <div style={{ marginTop: 'auto', display: 'flex', gap: '1rem' }}>
            <button
                className="btn btn-outline"
                style={{ flex: 1, padding: '1rem', fontWeight: '800' }}
                onClick={onViewPortfolio}
            >
                Portfolio
            </button>
            <button
                className="btn btn-primary"
                style={{ flex: 2, padding: '1rem', fontWeight: '800', gap: '0.5rem' }}
                onClick={onBook}
            >
                Book Slot <ChevronRight size={18} />
            </button>
        </div>
    </div>
);

export default SearchDoctors;

const PortfolioModal = ({ doctor, onClose }) => {
    const [reviews, setReviews] = useState([]);
    const [loadingReviews, setLoadingReviews] = useState(true);

    useEffect(() => {
        fetchReviews();
    }, [doctor.id]);

    const fetchReviews = async () => {
        try {
            const data = await api.get(`/reviews/doctor/${doctor.id}/`);
            setReviews(data);
        } catch (error) {
            console.error("Failed to fetch reviews:", error);
        } finally {
            setLoadingReviews(false);
        }
    };

    return (
        <Modal
            isOpen={true}
            onClose={onClose}
            title="Practitioner Profile"
            subtitle="Professional credentials and expertise"
            maxWidth="800px"
        >
            <div style={{ padding: '0', maxHeight: '70vh', overflowY: 'auto', paddingRight: '1rem' }}>
