// ─── Helpers ────────────────────────────────────────────────────────────────
const MEDICAL_KW = new Set([
    'pain', 'ache', 'hurt', 'sore', 'fever', 'cough', 'cold', 'nausea', 'vomit', 'headache',
    'dizzy', 'rash', 'itch', 'swelling', 'tired', 'fatigue', 'weak', 'chest', 'stomach', 'back',
    'head', 'throat', 'nose', 'ear', 'eye', 'skin', 'blood', 'breathing', 'breath', 'heart',
    'leg', 'arm', 'joint', 'muscle', 'diarrhea', 'constipation', 'anxiety', 'stress', 'depressed',
    'sleep', 'insomnia', 'burning', 'sharp', 'dull', 'throbbing', 'constant', 'worse', 'better',
    'sudden', 'gradual', 'yesterday', 'today', 'week', 'days', 'morning', 'night', 'yes', 'no',
    'none', 'nothing', 'fine', 'okay', 'bad', 'severe', 'mild', 'right', 'left', 'both', 'side',
    'pressure', 'tight', 'heavy', 'moderate', 'eating', 'moving', 'resting', 'spreading', 'started',
]);
const GREETING_RE = /^(hi+|hello+|hey+|hii+|helo|sup|howdy|good\s*(morning|afternoon|evening|night))\W*$/i;
const NO_VOWEL_RE = /^[^aeiou\s]{4,}$/i;
const BOOKING_KW = ['book', 'appointment', 'consult', 'visit', 'checkup', 'schedule'];


// Extra words that are valid non-medical responses (for follow-up questions)
const VALID_RESPONSE_WORDS = new Set([
    'yes', 'no', 'nope', 'yep', 'yeah', 'none', 'nothing', 'not', 'never', 'always', 'sometimes',
    'left', 'right', 'both', 'side', 'upper', 'lower', 'middle', 'center', 'all over', 'everywhere',
    'male', 'female', 'man', 'woman', 'boy', 'girl', 'old', 'young',
    'morning', 'night', 'evening', 'afternoon', 'daily', 'weekly', 'constant', 'always',
    'better', 'worse', 'same', 'improving', 'worsening',
    'maybe', 'possibly', 'unsure', 'unknown', 'idk',
]);

// OFF-TOPIC patterns that should always be blocked
const OFF_TOPIC_RE = /(who is|what is|capital of|president|prime minister|cricket|football|movie|song|weather|stock|bitcoin|tell me a joke|how are you|what can you do)/i;

function isGarbage(t, isFollowUp = false, allDoctors = []) {
    const s = t.trim().toLowerCase();
    if (!s) return true;

    // Check for booking intent first
    const hasBookingKw = BOOKING_KW.some(kw => s.includes(kw));
    const hasDoctorName = allDoctors.some(doc => s.includes(doc.doctor_name.toLowerCase()));
    if (hasBookingKw || hasDoctorName) return false;

    // Pure numbers are valid (age, severity scale)

    if (/^\d{1,3}$/.test(s)) return false;

    // Too short to mean anything
    if (s.length <= 2) return true;

    // Greetings — not garbage, handled separately
    if (GREETING_RE.test(s)) return false;

    // Explicitly off-topic
    if (OFF_TOPIC_RE.test(s)) return true;

    // No vowels at all = random chars (e.g. "asdf", "bcdfg")
    if (NO_VOWEL_RE.test(s)) return true;

    // Repeating character spam (e.g. "aaaaaaa", "hahaha")
    if (s.length > 3 && new Set(s.replace(/\s/g, '').split('')).size <= 2) return true;

    // For follow-up questions (after step 0), also accept simple valid responses
    if (isFollowUp) {
        const words = (s.match(/\b\w+\b/g) || []);
        if (words.some(w => VALID_RESPONSE_WORDS.has(w) || MEDICAL_KW.has(w))) return false;
    }

    // Must contain at least one real medical keyword for the first symptom question
    const words = (s.match(/\b\w+\b/g) || []);
    if (words.some(w => MEDICAL_KW.has(w))) return false;

    // Short with no known words = likely garbage
    if (s.length < 8) return true;

    // Long enough to be a sentence but no medical content — still garbage for symptom field
    // Allow if it contains common English words (basic sentence validity)
    const COMMON_WORDS = new Set(['i', 'my', 'have', 'has', 'been', 'feel', 'feeling', 'am', 'is', 'are', 'the', 'a', 'an', 'in', 'on', 'at', 'for', 'since', 'from', 'with', 'and', 'or', 'but', 'it', 'its', 'this', 'that', 'there', 'here', 'to', 'of', 'do']);
    const hasCommonWords = words.filter(w => COMMON_WORDS.has(w)).length >= 2;
    if (hasCommonWords && words.length >= 3) return false;

    return true; // DEFAULT: reject if nothing passed
}

function getGarbageHint(t, isFollowUp = false) {
    const s = t.trim().toLowerCase();
    if (OFF_TOP_RE.test(s)) return 'I can only help with health questions — please describe your symptoms.';
    if (NO_VOWEL_RE.test(s)) return 'That looks like random characters. Please describe a symptom.';
    if (s.length <= 2) return 'Too short — try: "I have a headache and fever".';
    if (isFollowUp) return 'Please answer the question above, or type your symptom.';
    return 'Please describe what you\'re feeling — e.g. "I have chest pain and feel dizzy".';
}

// Rich text renderer
function RichText({ text, userBubble }) {
    if (!text) return null;
    const lines = text.split('\n');
    return (
        <div className="rt">
            {lines.map((line, i) => {
                const t = line.trim();
                if (t === '---') return <hr key={i} className="rt-divider" />;
                if (!t) return <div key={i} className="rt-spacer" />;

                const sectionM = t.match(/^([📋🔍⚡🏠🚩👨‍⚕️⚠️🚨🔴🟢🟡🟠])\s*\*?\*?(.+?)\*?\*?$/u);
                if (sectionM) return (
                    <div key={i} className="rt-section">
                        <span className="rt-section-emoji">{sectionM[1]}</span>
                        <span><strong>{renderInline(sectionM[2])}</strong></span>
                    </div>
                );

                const numM = t.match(/^(\d+)\.\s+(.+)/);
                if (numM) return (
                    <div key={i} className="rt-item">
                        <span className="rt-num">{numM[1]}.</span>
                        <span>{renderInline(numM[2])}</span>
                    </div>
                );

                if (t.startsWith('- ') || t.startsWith('• ')) return (
                    <div key={i} className="rt-item">
                        <span className="rt-bullet" />
                        <span>{renderInline(t.slice(2))}</span>
                    </div>
                );

                if (t.startsWith('*') && t.endsWith('*') && !t.startsWith('**')) return (
                    <p key={i} className="rt-disclaimer">{t.slice(1, -1)}</p>
                );

                return <p key={i} className="rt-para">{renderInline(t)}</p>;
            })}
        </div>
    );
}

function renderInline(text) {
    const parts = []; const re = /(\*\*(.+?)\*\*|\*(.+?)\*)/g;
    let last = 0, m, k = 0;
    while ((m = re.exec(text)) !== null) {
        if (m.index > last) parts.push(<span key={k++}>{text.slice(last, m.index)}</span>);
        if (m[0].startsWith('**')) parts.push(<strong key={k++}>{m[2]}</strong>);
        else parts.push(<em key={k++}>{m[3]}</em>);
        last = re.lastIndex;
    }
    if (last < text.length) parts.push(<span key={k++}>{text.slice(last)}</span>);
    return parts.length ? parts : text;
}

const hasEmergency = (t) => {
    const l = (t || '').toLowerCase();
    return l.includes('🔴') || l.includes('🚨') || l.includes('emergency medicine') || l.includes('call 112');
};

