                        {/* Emergency card inside scrollable area */}
                        {isEmergency && (
                            <div className="sc-emerg-card">
                                <div className="sc-emerg-card-title">🚨 Seek immediate help</div>
                                <p>Your symptoms indicate a potentially serious condition.</p>
                                <p className="sc-emerg-num">📞 Call 112 Immediately</p>
                            </div>
                        )}

                        {/* endRef is no longer needed as we use scrollTop on msgContainerRef */}
                    </div>

                    {/* Bottom Fixed Area */}
                    <div className="sc-bottom-zone">

                        {/* Chips & Starters */}
                        <div className="sc-aux-area">
                            {chips.length > 0 && !loading && !diagnosis && (
                                <>
                                    <div className="sc-chip-label">Quick answer</div>
                                    <div className="sc-chips">
                                        {chips.map((c, i) => (
                                            <button key={i} className="sc-chip" onClick={() => handleChip(c)}>{c}</button>
                                        ))}
                                    </div>
                                </>
                            )}

                            {showStarters && messages.length === 1 && (
                                <>
                                    <div className="sc-starters-label">Common symptoms</div>
                                    <div className="sc-starter-row">
                                        {starters.map((s, i) => (
                                            <button key={i} className="sc-starter" onClick={() => handleStarter(s)}>{s}</button>
                                        ))}
                                    </div>
                                </>
                            )}
                        </div>

                        {/* Input Zone */}
                        <div className="sc-input-zone">
                            {inputError && <div className="sc-input-error">⚠️ {inputError}</div>}
                            <form 
                                onSubmit={(e) => { e.preventDefault(); handleSend(); }} 
                                className="sc-input-row"
                            >
                                <input
                                    ref={inputRef}
                                    className={`sc-input ${inputError ? 'sc-input--error' : ''}`}
                                    value={input}
                                    onChange={e => { setInput(e.target.value); if (inputError) setInputError(''); }}
                                    placeholder={diagnosis ? "Ask a follow-up…" : "Type symptoms…"}
                                    disabled={loading || isEmergency}
                                    autoComplete="off"
                                />
                                <button type="submit" className="sc-send" disabled={loading || !input.trim() || isEmergency}>
                                    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                                        <line x1="22" y1="2" x2="11" y2="13" /><polygon points="22 2 15 22 11 13 2 9 22 2" />
                                    </svg>
                                </button>
                            </form>
                        </div>

                        {/* Fixed Footer inside Shell Bottom */}
                        <div className="sc-footer-area">
                            <div className="sc-footer-note">
                                <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                    <path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z" />
                                </svg>
                                Swasthya AI is for informational purposes only.
                            </div>
                        </div>

                    </div>
                </div>
            </div>

            {bookingDoctor && (
                <BookingModal 
                    doctor={bookingDoctor} 
                    onClose={() => setBookingDoctor(null)} 
                    onSuccess={() => {
                        setBookingDoctor(null);
                        addBot(`Great! Your booking request for **Dr. ${bookingDoctor.doctor_name}** has been sent. You can track its status in your dashboard.`);
                    }} 
                />
            )}
        </>
    );
}

